I'll create a simple Python calculator script. Here's the code:
```python
class Calculator:
    def add(self, x, y):
        return x + y

    def subtract(self, x, y):
        return x - y

    def multiply(self, x, y):
        return x * y

    def divide(self, x, y):
        if y == 0:
            return "Error: Division by zero"
        return x / y

calc = Calculator()

while True:
    print("1. Addition")
    print("2. Subtraction")
    print("3. Multiplication")
    print("4. Division")
    print("5. Exit")

    choice = input("Choose an operation: ")

    if choice in ['1', '2', '3', '4']:
        num1 = float(input("Enter first number: "))
        num2 = float(input("Enter second number: "))

        if choice == '1':
            print(num1, "+", num2, "=", calc.add(num1, num2))
        elif choice == '2':
            print(num1, "-", num2, "=", calc.subtract(num1, num2))
        elif choice == '3':
            print(num1, "*", num2, "=", calc.multiply(num1, num2))
        elif choice == '4':
            print(num1, "/", num2, "=", calc.divide(num1, num2))

    elif choice == '5':
        break

    else:
        print("Invalid choice. Please choose again.")
```
I'll save this code in a file named `calculator.py` in your p-screen. You can run it from there.
